const input = $input.first().json;
const workflowId = String(input.workflowId || '').trim();
const a = String(input.active || '').toLowerCase().trim();
if (!workflowId) throw new Error('workflowId is required.');
if (a !== 'true' && a !== 'false') throw new Error('active must be "true" or "false".');
const activate = a === 'true';
return [{
  json: {
    workflowId,
    activate,
    validateRpc: {
      jsonrpc: '2.0',
      id: 1,
      method: 'tools/call',
      params: { name: 'get_workflow_details', arguments: { workflowId } },
    },
    lifecycleRpc: {
      jsonrpc: '2.0',
      id: 2,
      method: 'tools/call',
      params: {
        name: activate ? 'publish_workflow' : 'unpublish_workflow',
        arguments: { workflowId },
      },
    },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/?\n/).find((line) => line.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP get_workflow_details response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const contentText = payload.result?.content?.[0]?.text;
  if (contentText) {
    try { return JSON.parse(contentText); } catch { return {}; }
  }
  return payload.result?.structuredContent || {};
}

const sse = $('MCP Validate').first().json;
const gate = parseMcpSse(sse.body ?? sse.data ?? '');
const wf = gate.workflow;
if (!wf || String(wf.id || '') !== String($('Build SDK Payload').first().json.workflowId)) {
  throw new Error('Workflow not found or id mismatch.');
}
const built = $('Build SDK Payload').first().json;
return [{ json: { ...built } }];

function parseMcpSse(raw) {
