  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const contentText = payload.result?.content?.[0]?.text;
  if (contentText) {
    try { return JSON.parse(contentText); } catch { return {}; }
  }
  return payload.result?.structuredContent || {};
}

const sse = $input.first().json;
const out = parseMcpSse(sse.body ?? sse.data ?? '');
const want = $('Build SDK Payload').first().json.activate;
return [{
  json: {
    success: out.success !== false,
    workflowId: out.workflowId,
    activated: want,
    error: out.error || '',
    response: out.error ? String(out.error) : (want ? 'Published (activated) workflow.' : 'Unpublished (deactivated) workflow.'),
  },
}];
